sequence.script:
var preferences =
  java.util.prefs.Preferences
    .userRoot()
    .node("telco-ai/partner-token-ledger");

var ledgerKey = String(
  mc.getProperty("aiQuotaLedgerKey") || ""
);

var before = Number(
  mc.getProperty("aiTokensUsedBefore") || 0
);

var current = Number(
  mc.getProperty("aiTotalTokens") || 0
);

if (!isFinite(before) || before < 0) {
  before = 0;
}

if (!isFinite(current) || current < 0) {
  current = 0;
}

before = Math.floor(before);
current = Math.floor(current);

var after = before + current;

if (ledgerKey !== "") {
  preferences.putLong(
    ledgerKey,
    after
  );

  /*
   * The in-memory Preferences state is immediately visible.
   * Attempt persistence without failing the AI request if the
   * backing store is temporarily unavailable.
   */
  try {
    preferences.flush();
  } catch (ignored) {
  }
}

var quota = Number(
  mc.getProperty("partnerDailyTokenQuota") ||
  100000
);

mc.setProperty(
  "aiTokensUsedAfter",
  String(after)
);

mc.setProperty(
  "aiTokensRemaining",
  String(
    Math.max(0, quota - after)
  )
);
